css:
* { margin: 0; padding: 0; box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; }
body { background: #fafbff; color: #1a1a2e; }
.navbar { display: flex; justify-content: space-between; align-items: center; padding: 24px 60px; }
.brand { font-size: 19px; font-weight: 800; }
.nav-links { display: flex; gap: 28px; }
.nav-links a { color: #999; text-decoration: none; font-size: 14px; font-weight: 600; }
.nav-links a.active { color: #6366f1; }
.hero { padding: 50px 60px 70px; max-width: 760px; }
.badge { display: inline-block; color: #6366f1; font-size: 12px; font-weight: 800; letter-spacing: 0.18em; margin-bottom: 24px; }
.hero h1 { font-size: 50px; font-weight: 800; line-height: 1.25; margin-bottom: 20px; }
.hero h1 span { color: #6366f1; }
.hero p { color: #888; font-size: 16px; line-height: 1.8; max-width: 540px; }
.case-studies { padding: 0 60px 70px; }
.case-studies h2 { font-size: 28px; font-weight: 800; margin-bottom: 30px; }
.case-grid { display: flex; flex-direction: column; gap: 24px; }
.case-card { display: grid; grid-template-columns: 240px 1fr; gap: 28px; background: white; border: 1px solid #eef0f5; border-radius: 20px; padding: 24px; cursor: pointer; align-items: center; }
.case-img { aspect-ratio: 4/3; background: linear-gradient(150deg, #eef1ff, #e0e7ff); border-radius: 14px; display: flex; align-items: center; justify-content: center; font-size: 50px; }
.cat { display: block; color: #6366f1; font-size: 11px; font-weight: 800; text-transform: uppercase; letter-spacing: 0.08em; margin-bottom: 8px; }
.case-card h3 { font-size: 20px; font-weight: 700; margin-bottom: 10px; line-height: 1.4; }
.case-card p { color: #888; font-size: 14px; line-height: 1.7; margin-bottom: 14px; }
.tags { display: flex; gap: 8px; flex-wrap: wrap; }
.tags span { background: #eef1ff; color: #6366f1; font-size: 11.5px; font-weight: 700; padding: 5px 12px; border-radius: 999px; }
.process { padding: 70px 60px; background: white; }
.process h2 { font-size: 28px; font-weight: 800; text-align: center; margin-bottom: 36px; }
.process-steps { display: grid; grid-template-columns: repeat(auto-fit, minmax(180px, 1fr)); gap: 24px; max-width: 1000px; margin: 0 auto; }
.step { text-align: center; }
.snum { display: inline-block; font-size: 13px; font-weight: 800; color: #6366f1; background: #eef1ff; padding: 6px 14px; border-radius: 999px; margin-bottom: 14px; }
.step h3 { font-size: 17px; font-weight: 700; margin-bottom: 8px; }
.step p { color: #888; font-size: 13px; line-height: 1.6; }
.contact { text-align: center; padding: 80px 60px; }
.contact h2 { font-size: 28px; font-weight: 800; margin-bottom: 10px; }
.contact p { color: #888; font-size: 14px; margin-bottom: 26px; }
.contact button { background: #6366f1; color: white; border: none; padding: 15px 32px; border-radius: 999px; font-size: 14px; font-weight: 700; cursor: pointer; }
.modal { position: fixed; inset: 0; background: rgba(26,26,46,0.5); display: none; align-items: center; justify-content: center; padding: 20px; z-index: 10; }
.modal.show { display: flex; }
.modal-content { background: white; border-radius: 20px; padding: 30px; max-width: 440px; width: 100%; }
.modal-img { aspect-ratio: 4/3; background: linear-gradient(150deg, #eef1ff, #e0e7ff); border-radius: 14px; display: flex; align-items: center; justify-content: center; font-size: 60px; margin-bottom: 16px; }
.modal-content h2 { font-size: 22px; font-weight: 800; margin: 8px 0 12px; }
.modal-content p { color: #888; font-size: 14px; line-height: 1.7; margin-bottom: 22px; }
.close-btn { background: #6366f1; color: white; border: none; padding: 12px 28px; border-radius: 999px; font-size: 14px; font-weight: 700; cursor: pointer; width: 100%; }
@media (max-width: 900px) { .navbar, .hero, .case-studies, .process, .contact { padding-left: 24px; padding-right: 24px; } .nav-links { display: none; } .hero h1 { font-size: 32px; } .case-card { grid-template-columns: 1fr; } }

