const cases = [
  { img: '📊', cat: 'Mobil Uygulama', title: 'FinTrack — Bütçe Takip Uygulaması', desc: '3 ay süren araştırma ve test süreciyle kullanıcıların işlem giriş süresini %40 azalttık. Kullanıcı görüşmeleri, kart sıralama ve A/B testler kullanıldı.' },
  { img: '🛒', cat: 'E-Ticaret', title: 'ShopEasy — Ödeme Akışı Yenileme', desc: 'Mevcut ödeme akışındaki sürtünme noktalarını analiz ederek yeniden tasarladık. Sonuç: sepetten çıkma oranında %25 azalma, dönüşümde %18 artış.' },
  { img: '🏥', cat: 'Sağlık', title: 'MedConnect — Hasta Randevu Sistemi', desc: 'WCAG erişilebilirlik standartlarına uygun, büyük dokunma alanları ve sesli yönlendirme içeren bir randevu sistemi tasarladık.' }
];

function openCase(el) {
  const title = el.querySelector('h3').textContent;
  const data = cases.find(c => c.title === title);
  if (!data) return;
  document.getElementById('modalImg').textContent = data.img;
  document.getElementById('modalCat').textContent = data.cat;
  document.getElementById('modalTitle').textContent = data.title;
  document.getElementById('modalDesc').textContent = data.desc;
  document.getElementById('modal').classList.add('show');
}

function closeModal(e) {
  if (e.target.id === 'modal' || e.target.classList.contains('close-btn')) {
    document.getElementById('modal').classList.remove('show');
  }
}

